#include <stdio.h>
#define MOD 1000000007
int countLuckyDigits(int x) {
    int count = 0;
    while (x > 0) {
        int digit = x % 10;
        if (digit == 4 || digit == 7) {
            count++;
        }
        x /= 10;
    }
    return count;
}
int isLucky(int x) {
    while (x > 0) {
        int digit = x % 10;
        if (digit != 4 && digit != 7) {
            return 0;
        }
        x /= 10;
    }
    return 1;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        int count = 0;
        for (int i = L; i <= R; i++) {
            int luckyDigits = countLuckyDigits(i);
            if (isLucky(luckyDigits)) {
                count++;
            }
        }
        printf("%d\n", count % MOD);
    }
    return 0;
}

