import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static int countLuckyDigits(int x) {
        int count = 0;
        while (x > 0) {
            int digit = x % 10;
            if (digit == 4 || digit == 7) {
                count++;
            }
            x /= 10;
        }
        return count;
    }
    public static boolean isLucky(int x) {
        while (x > 0) {
            int digit = x % 10;
            if (digit != 4 && digit != 7) {
                return false;
            }
            x /= 10;
        }
        return true;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int count = 0;
            for (int i = L; i <= R; i++) {
                int luckyDigits = countLuckyDigits(i);
                if (isLucky(luckyDigits)) {
                    count++;
                }
            }
            System.out.println(count % MOD);
        }
    }
}

